// Извлекаем чистую команду из ответа AI-транслятора.

const toText = (v) => String(v ?? '').trim()

let agentOutput = ''
try { agentOutput = toText($('Транслятор команд').first().json.output ?? $('Транслятор команд').first().json.text ?? '') } catch (_) {}

const triggerData = $('Триггер Telegram').first().json
const originalText = toText((triggerData.message || {}).text || '')

if (!agentOutput) {
  return { json: { translatedCommand: originalText, originalText, isTranslated: false } }
}

// Очищаем: убираем markdown, бэктики, лишние пробелы и переносы
let cleaned = agentOutput
  .replace(/```[\s\S]*?```/g, '')
  .replace(/`([^`]*)`/g, '$1')
  .replace(/^\s*[/]/, '/')
  .split('\n')[0]
  .trim()

// Если результат начинается с /task или /abort — это команда
const looksLikeCommand = /^\/(task|abort)\b/.test(cleaned)

// Если AI вернул не-команду — используем оригинал
const finalCommand = looksLikeCommand ? cleaned : originalText

return {
  json: {
    translatedCommand: finalCommand,
    originalText,
    isTranslated: looksLikeCommand,
    agentRawOutput: agentOutput,
  },
}

// Главный парсер входящих Telegram-сообщений.
// Все ответы на вопросы — через /task --answer="..."
// Все команды — через /command --flags="..."

const input = $('Триггер Telegram').first().json
const msg = input.message || {}
let rawText = String(msg.text || '').trim()
// Если AI-транслятор вернул команду — используем её вместо сырого текста
try {
  const translated = $input.first().json.translatedCommand
  if (translated && /^\/(task|abort)\b/.test(translated)) {
    rawText = String(translated).trim()
  }
} catch (_) {}

function parseCommand(text) {
  const match = text.match(/^\/([a-zA-Z0-9_]+)(?:@\w+)?(?:\s+|$)/)
  if (!match) return { type: null, textAfterCommand: text }
  return { type: match[1], textAfterCommand: text.slice(match[0].length).trim() }
}

function parseTokens(text) {
  const flags = {}
  const args = []
  const regex = /--([a-zA-Z0-9_-]+)(?:=(?:"((?:[^"\\]|\\.)*)"|'((?:[^'\\]|\\.)*)'|([^\s"']+)))?|"((?:[^"\\]|\\.)*)"|'((?:[^'\\]|\\.)*)'|([^\s]+)/g
  let match
  while ((match = regex.exec(text)) !== null) {
    if (match[1]) {
      flags[match[1]] = match[2] ?? match[3] ?? match[4] ?? true
      continue
    }
    const value = match[5] ?? match[6] ?? match[7]
    if (value !== undefined) args.push(value)
  }
  return { flags, args }
}

if (!rawText.startsWith('/')) {
  return [{ json: {
    mode: 'parse_error',
    rawText,
    replyText: 'Не удалось распознать команду. Используйте /task --prompt="..." или /task --answer="...".'
  }}]
}

const command = parseCommand(rawText)
if (!command.type) {
  return [{ json: {
    mode: 'parse_error',
    rawText,
    replyText: 'Команда не распознана. Используйте /task или /abort с флагами --flag="...".'
  }}]
}

const parsed = parseTokens(command.textAfterCommand)

return [{ json: {
  mode: 'command_candidate',
  rawText,
  commandType: command.type,
  flags: parsed.flags,
  args: parsed.args,
  prompt: String(parsed.flags.prompt || '').trim(),
  answerText: String(parsed.flags.answer || '').trim(),
  parentTaskId: String(parsed.flags.parent_task_key || '').trim(),
  parentMatchText: String(parsed.flags.parent_match_text || '').trim(),
  newSessionRequested: Boolean(
    parsed.flags['new_session'] || parsed.flags['new-session'] ||
    parsed.flags['fresh_session'] || parsed.flags['fresh-session']
  )
}}]

// Связывает answer_candidate с pending-задачей.
// Ответ приходит только в формате /task --answer="..." или /task --task_key="xxx" --answer="..."

const candidate = $input.first().json
const pendingTasks = $('Получаем задачи с ожиданием ответа').all().map((item) => item.json)

function parsePendingMeta(task) {
  try { return JSON.parse(String(task.pending_options_json || '{}')) } catch { return {} }
}

// Определяем какую задачу: --task_key или авто-выбор если одна
const flags = candidate.flags || {}
const specifiedTaskKey = String(flags.task_key || '').trim()
let targetTaskKey = specifiedTaskKey

if (!targetTaskKey && pendingTasks.length === 1) {
  targetTaskKey = String(pendingTasks[0].task_key || '').trim()
}

if (!targetTaskKey) {
  const taskList = pendingTasks.map((task) => `- <code>${task.task_key || 'неизвестно'}</code>`).join('\n')
  return [{ json: { mode: 'parse_error', replyText: `Несколько задач ожидают ответа:\n${taskList}\n\nУкажите задачу: /task --task_key="task-key" --answer="ваш ответ"` } }]
}

const task = pendingTasks.find((item) => String(item.task_key || '').trim() === targetTaskKey)
if (!task) {
  return [{ json: { mode: 'parse_error', replyText: `Не удалось найти задачу <code>${targetTaskKey}</code> среди ожидающих ответа.` } }]
}

const pendingMeta = parsePendingMeta(task)
const requestId = String(pendingMeta.requestId || '').trim()
const interactionType = Array.isArray(pendingMeta.questions) ? 'question' : String(pendingMeta.type || 'permission').trim()

if (!requestId) {
  return [{ json: { mode: 'parse_error', replyText: `У задачи <code>${targetTaskKey}</code> повреждены данные pending интеракции.` } }]
}

return [{
  json: {
    mode: interactionType + '_candidate',
    rawText: candidate.rawText,
    targetTaskKey,
    answerText: candidate.answerText,
    rejectRequested: String(candidate.answerText || '').trim().toLowerCase() === '/reject',
    interactionType,
    pendingMeta,
  }
}]

// Готовим запрос на прерывание задачи.
// task_key извлекается из флага --task_key.

const parsed = $input.first().json
const flags = parsed.flags || {}
const inputTaskKey = String(flags.task_key || '').trim()

return [{ json: { mode: 'abort_request', rawText: parsed.rawText, targetTaskKey: inputTaskKey } }]

// Определяем какую задачу прерывать.
//   явный task-key      → указанная задача
//   без task-key         → если одна — авто-выбор, несколько — уточнение у пользователя

const abortRequest = $('Готовим запрос прерывания').first().json
const activeRunning = $('Получаем работающие задачи').all().map((item) => item.json)
const inputTaskKey = String(abortRequest.targetTaskKey || '').trim()

// Если нет работающих — проверяем queued (повторяющиеся с --interval)
let queuedRecurring = []
try { queuedRecurring = $('Получаем все задачи').all().map(i => i.json).filter(t => String(t.status || '').trim() === 'queued') } catch(_) {}

if (activeRunning.length === 0 && queuedRecurring.length === 0) {
  return [{ json: { mode: 'parse_error', replyText: 'Нет ни работающих, ни ожидающих задач.' } }]
}

// Если только queued — отменяем их напрямую (без сессии)
if (activeRunning.length === 0) {
  if (inputTaskKey) {
    const t = queuedRecurring.find(item => String(item.task_key || '').trim() === inputTaskKey)
    if (!t) return [{ json: { mode: 'parse_error', replyText: `Задача <code>${inputTaskKey}</code> не найдена в очереди.` } }]
    return [{ json: { mode: 'cancel_queued', targetTaskKey: inputTaskKey, replyText: `Повторяющаяся задача <code>${inputTaskKey}</code> отменена.` } }]
  }
  if (queuedRecurring.length === 1) {
    const tk = String(queuedRecurring[0].task_key || '').trim()
    return [{ json: { mode: 'cancel_queued', targetTaskKey: tk, replyText: `Повторяющаяся задача <code>${tk}</code> отменена.` } }]
  }
  const list = queuedRecurring.map(t => `- <code>${t.task_key || '?'}</code>`).join('\n')
  return [{ json: { mode: 'parse_error', replyText: `В очереди несколько задач:\n${list}\n\nУточните: /abort --task_key="task-key"` } }]
}

if (inputTaskKey) {
  const task = activeRunning.find((item) => String(item.task_key || '').trim() === inputTaskKey)
  if (!task) {
    return [{ json: { mode: 'parse_error', replyText: `Не удалось найти работающую задачу <code>${inputTaskKey || 'неизвестно'}</code>.` } }]
  }
  return [{ json: { mode: 'answer', targetTaskKey: inputTaskKey, replyText: `Задача <code>${inputTaskKey}</code> будет прервана.` } }]
}

if (activeRunning.length === 1) {
  const taskKey = String(activeRunning[0].task_key || '').trim()
  return [{ json: { mode: 'answer', targetTaskKey: taskKey, replyText: `Задача <code>${taskKey}</code> будет прервана.` } }]
}

const taskList = activeRunning.map((item) => `- <code>${item.task_key || 'неизвестно'}</code>`).join('\n')
return [{ json: { mode: 'parse_error', replyText: `Работает несколько задач:\n${taskList}\n\nУточните: /abort --task_key="task-key"` } }]

// Парсим ответ пользователя на question-интеракцию OpenCode.
// Поддерживает:
//   - один вопрос → простой ответ (номер/текст варианта)
//   - несколько вопросов → ответы через ||
//   - /reject → отклонение вопроса
//   - множественный выбор → варианты через &&

const parsed = $('Готовим ожидающую интеракцию').first().json
const pendingMeta = parsed.pendingMeta || {}
const normalized = String(parsed.answerText || '').trim()

// Отклонение вопроса
if (parsed.rejectRequested) {
  const updatedPendingMeta = {
    ...pendingMeta,
    answers: null,
    rejectRequested: true,
    answeredAt: new Date().toISOString(),
    rawAnswer: parsed.rawText,
  }
  return [{ json: { mode: 'answer', targetTaskKey: parsed.targetTaskKey, updatedPendingOptionsJson: JSON.stringify(updatedPendingMeta), replyText: `Вопрос по задаче <code>${parsed.targetTaskKey || 'неизвестно'}</code> отклонён.` } }]
}

// Разбирает один токен ответа: число → номер варианта, текст → поиск по label
function parseAnswerToken(token, question) {
  const value = String(token || '').trim()
  if (!value) return null
  const options = Array.isArray(question.options) ? question.options : []
  if (options.length === 0) return value
  if (/^\d+$/.test(value)) {
    const option = options[Number(value) - 1]
    return option ? String(option.label || '').trim() : null
  }
  const matched = options.find((option) => String(option.label || '').trim().toLowerCase() === value.toLowerCase())
  if (matched) return String(matched.label || '').trim()
  return question.custom !== false ? value : null
}

// Разбирает ответ на один вопрос: возвращает { answers } или { error }
function parseQuestionAnswer(text, question) {
  const value = String(text || '').trim()
  if (!value) return { error: 'Ответ не должен быть пустым.' }
  const options = Array.isArray(question.options) ? question.options : []
  if (options.length === 0) return { answers: [value] }
  const tokens = question.multiple ? value.split(/\s*&&\s*/).filter(Boolean) : [value]
  const answers = []
  for (const token of tokens) {
    const parsedToken = parseAnswerToken(token, question)
    if (!parsedToken) return { error: `Не удалось распознать вариант ответа: ${token}` }
    if (!answers.includes(parsedToken)) answers.push(parsedToken)
  }
  if (!question.multiple && answers.length !== 1) {
    return { error: 'Нужно выбрать ровно один вариант ответа.' }
  }
  return { answers }
}

const questions = Array.isArray(pendingMeta.questions) ? pendingMeta.questions : []
if (questions.length === 0) {
  return [{ json: { mode: 'parse_error', replyText: `У задачи <code>${parsed.targetTaskKey || 'неизвестно'}</code> повреждены данные pending вопроса.` } }]
}

// Один вопрос или несколько (через ||)
let answersResult
if (questions.length === 1) {
  answersResult = parseQuestionAnswer(normalized, questions[0])
} else {
  const lines = normalized.split(/\s*\|\|\s*/).map((line) => line.trim()).filter(Boolean)
  if (lines.length !== questions.length) {
    answersResult = { error: `Нужно прислать ${questions.length} ответов через || в том же порядке, что и вопросы.` }
  } else {
    const answers = []
    for (let index = 0; index < questions.length; index += 1) {
      const parsedLine = parseQuestionAnswer(lines[index], questions[index])
      if (parsedLine.error) { answersResult = parsedLine; break }
      answers.push(parsedLine.answers)
    }
    answersResult = answersResult || { answers }
  }
}

if (answersResult.error) {
  return [{ json: { mode: 'parse_error', replyText: `Не удалось разобрать ответ для задачи <code>${parsed.targetTaskKey || 'неизвестно'}</code>: ${answersResult.error}` } }]
}

const updatedPendingMeta = {
  ...pendingMeta,
  answers: answersResult.answers,
  rejectRequested: false,
  answeredAt: new Date().toISOString(),
  rawAnswer: parsed.rawText,
}

return [{ json: { mode: 'answer', targetTaskKey: parsed.targetTaskKey, updatedPendingOptionsJson: JSON.stringify(updatedPendingMeta), replyText: `Ответ по задаче <code>${parsed.targetTaskKey || 'неизвестно'}</code> сохранён. Продолжаю выполнение.` } }]

// Парсим ответ пользователя на permission-интеракцию OpenCode.
// Варианты: 1/once, 2/always, 3/reject (с опциональным комментарием).

const parsed = $('Готовим ожидающую интеракцию').first().json
const pendingMeta = parsed.pendingMeta || {}
const normalized = String(parsed.answerText || '').trim()

if (!normalized) {
  return [{ json: { mode: 'parse_error', replyText: 'Ответ не должен быть пустым.' } }]
}

const lower = normalized.replace(/^\//, '').toLowerCase()
let reply = ''
let message = ''

if (/^(1|once|allow once|раз|один раз|разрешить один раз)(?:\b|$)/i.test(lower)) {
  reply = 'once'
} else if (/^(2|always|remember|always allow|всегда|запомнить|разрешить всегда)(?:\b|$)/i.test(lower)) {
  reply = 'always'
} else {
  const rejectMatch = lower.match(/^(3|reject|deny|no|отклонить|запретить)(?:[\s:,-]+([\s\S]*))?$/i)
  if (rejectMatch) {
    reply = 'reject'
    message = String(rejectMatch[2] || '').trim()
  }
}

if (!reply) {
  return [{ json: { mode: 'parse_error', replyText: `Не удалось разобрать permission-ответ для задачи <code>${parsed.targetTaskKey || 'неизвестно'}</code>: Для permission используйте один из вариантов: 1/once, 2/always, 3/reject.` } }]
}

const updatedPendingMeta = {
  ...pendingMeta,
  type: 'permission',
  reply,
  message,
  answeredAt: new Date().toISOString(),
  rawAnswer: parsed.rawText,
}

return [{ json: { mode: 'answer', targetTaskKey: parsed.targetTaskKey, updatedPendingOptionsJson: JSON.stringify(updatedPendingMeta), replyText: `Permission-ответ по задаче <code>${parsed.targetTaskKey || 'неизвестно'}</code> сохранён. Продолжаю выполнение.` } }]

// Проверяет допустимость команды по декларативному списку из «Задаём переменные».
// Каждый элемент allowed_commands: { command, require: [...] }
// usage для ошибок генерируется автоматически из command + require.

const vars = $('Задаём переменные').first().json
const allowedCommands = Array.isArray(vars.allowed_commands) ? vars.allowed_commands : []
const input = $input.item.json
// Пропускаем не-команды (parse_error и т.д.) насквозь
if (input.mode !== 'command_candidate') return { json: input }

const commandType = String(input.commandType || '').trim()
const flags = input.flags || {}

const flagFilled = (val) =>
  val !== undefined && val !== null && String(val).trim() !== ''

const patterns = allowedCommands.filter((p) => p.command === commandType)

if (patterns.length === 0) {
  const known = [...new Set(allowedCommands.map((p) => `/${p.command}`))].join(', ')
  return { json: { ...input, mode: 'parse_error', replyText: `Неизвестная команда${commandType ? ' /' + commandType : ''}. Доступные команды: ${known}.` } }
}

const satisfied = patterns.find((p) => {
  const rf = Array.isArray(p.require) ? p.require : [p.require]
  return rf.every((flag) => flagFilled(flags[flag]))
})

if (satisfied) {
  return { json: input }
}

// Генерируем usage на лету: /command --flag1 --flag2
const usages = patterns
  .map((p) => `/${p.command} ` + (Array.isArray(p.require) ? p.require : [p.require]).map((f) => `--${f}="..."`).join(' '))
  .join('\n  или ')

return { json: { ...input, mode: 'parse_error', replyText: `Команда /${commandType} требует обязательные флаги:\n  ${usages}` } }

// Нормализуем голосовую команду в формат Telegram-сообщения
const body = $input.first().json
const prompt = String(body.body?.prompt || body.prompt || '').trim()

// Используем 0 как placeholder — set-chat-id установит правильный chat_id позже
return {
  json: {
    message: {
      message_id: Date.now(),
      text: prompt,
      chat: { id: 0 },
      from: { id: 0, first_name: 'Voice' },
    },
    source: 'voice',
    rawText: prompt,
  },
}
